import Link from 'next/link';
import { getServerSession } from 'next-auth';

export default async function Navbar() {
  const session = await getServerSession();

  return (
    <nav className="bg-white shadow-md p-4">
      <div className="container mx-auto flex justify-between items-center">
        <Link href="/" className="text-xl font-bold text-blue-600">
          RestoManager
        </Link>
        <div className="space-x-4">
          <Link href="/restaurants" className="text-gray-700 hover:text-blue-600">
            Restaurants
          </Link>
          {session ? (
            <>
              <Link href="/orders" className="text-gray-700 hover:text-blue-600">
                Orders
              </Link>
              <Link href="/api/auth/signout" className="text-gray-700 hover:text-blue-600">
                Sign Out
              </Link>
            </>
          ) : (
            <Link href="/api/auth/signin" className="text-gray-700 hover:text-blue-600">
              Sign In
            </Link>
          )}
        </div>
      </div>
    </nav>
  );
}
import { withAuth } from "next-auth/middleware";

export default withAuth({
  pages: {
    signIn: "/auth/signin",
  },
});

export const config = {
  matcher: ["/dashboard/:path*", "/admin/:path*", "/orders/:path*"],
};
'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';

interface MenuItemFormProps {
  restaurantId: string;
  onSuccess?: () => void;
}

export default function MenuItemForm({ restaurantId, onSuccess }: MenuItemFormProps) {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [price, setPrice] = useState('');
  const [category, setCategory] = useState('');
  const [loading, setLoading] = useState(false);
  const router = useRouter();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      const res = await fetch('/api/menu-items', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name,
          description,
          price: parseFloat(price),
          category,
          restaurantId,
        }),
      });

      if (res.ok) {
        setName('');
        setDescription('');
        setPrice('');
        setCategory('');
        if (onSuccess) onSuccess();
        router.refresh();
      }
    } catch (error) {
      console.error('Error creating menu item:', error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4 bg-white p-6 rounded-lg shadow">
      <h3 className="text-lg font-semibold">Add Menu Item</h3>
      <div>
        <label className="block text-sm font-medium text-gray-700">Name</label>
        <input
          type="text"
          value={name}
          onChange={(e) => setName(e.target.value)}
          className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500"
          required
        />
      </div>
      <div>
        <label className="block text-sm font-medium text-gray-700">Description</label>
        <textarea
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500"
        />
      </div>
      <div>
        <label className="block text-sm font-medium text-gray-700">Price</label>
        <input
          type="number"
          step="0.01"
          value={price}
          onChange={(e) => setPrice(e.target.value)}
          className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500"
          required
        />
      </div>
      <div>
        <label className="block text-sm font-medium text-gray-700">Category</label>
        <input
          type="text"
          value={category}
          onChange={(e) => setCategory(e.target.value)}
          className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500"
          required
        />
      </div>
      <button
        type="submit"
        disabled={loading}
        className="w-full flex justify-center py-2 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 disabled:opacity-50"
      >
        {loading ? 'Adding...' : 'Add Item'}
      </button>
    </form>
  );
}
